INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '1. Explica las teorías del origen de la vida, las características de los seres vivos y las funciones de la célula en la organización de los sistemas de vida desde la ciencia y la diversidad cultural.', ARRAY['1.1. Describe las similitudes y diferencias entre las diversas teorías sobre el origen de la vida.', '1.2. Describe la estructura celular y su función.', '1.3. Describe las características de los seres vivos explicando la estructura y función de órganos y sistemas de su cuerpo.', '1.4. Describe los hechos científicos y los relaciona con su contexto natural y social.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '2. Diferencia entre las estructuras y las funciones de órganos y sistemas de los seres vivos.', ARRAY['2.1. Establece relaciones de similitud o diferencia entre las características de los seres vivos.', '2.2. Establece similitud entre las funciones de los diversos órganos y sistemas.', '2.3. Describe la estructura y funcionamiento de los sistemas digestivo, respiratorio, circulatorio, endocrino y nervioso.', '2.4. Explica la nutrición como proceso fundamental del aparato digestivo.', '2.5. Define la relación entre nutrición y digestión.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '3. Identifica su sexualidad y las manifestaciones físicas y sociales de su desarrollo.', ARRAY['3.1. Explica los factores de crecimiento y desarrollo de los seres vivos.', '3.2. Establece similitudes y diferencias entre crecimiento y desarrollo.', '3.3. Respeta las diferencias individuales y colectivas.', '3.4. Identifica el VIH-SIDA como una infección de transmisión sexual.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '4. Establece la relación entre vida saludable, prevención en el consumo de drogas y violencia intrafamiliar.', ARRAY['4.1. Identifica prácticas para una vida saludable.', '4.2. Reconoce las consecuencias del consumo de drogas, alcohol y tabaco.', '4.3. Identifica factores de riesgo y de protección en el consumo de drogas.', '4.4. Opina con respecto a las consecuencias sociales de la violencia intrafamiliar para la salud mental y física.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '5. Identifica las prácticas alimentarias y de salud que le permiten la prevención de enfermedades.', ARRAY['5.1. Practica hábitos alimentarios que favorecen la prevención de enfermedades.', '5.2. Explica qué es una dieta balanceada y la relaciona con la salud.', '5.3. Valora la vacunación como una forma para evitar enfermedades.', '5.4. Identifica técnicas para la conservación de alimentos.', '5.5. Relaciona la higiene con la prevención de enfermedades.', '5.6. Practica medidas para erradicar parásitos transmisores de enfermedades.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '6. Participa en actividades que promueven el rescate, el conocimiento, la protección, la conservación y el uso racional de los recursos naturales.', ARRAY['6.1. Promueve el derecho a un ambiente sano y de seguridad comunitaria.', '6.2. Describe la importancia del agua para los seres vivos.', '6.3. Explica la importancia de los ecosistemas en la supervivencia de la biodiversidad.', '6.4. Identifica los elementos nocivos para el entorno.', '6.5. Utiliza racionalmente los recursos naturales.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '7. Explica la relación entre materia y energía y su utilidad para el ser humano.', ARRAY['7.1. Relaciona el movimiento con la energía y la materia.', '7.2. Identifica fuentes de energía.', '7.3. Relaciona energía y trabajo.', '7.4. Explica la estructura y función del átomo.', '7.5. Opina acerca de la necesidad de la energía para la vida.']),
('Cuarto Grado', 'Ciencias Naturales y Tecnología', '8. Utiliza la tecnología de su cultura y de otras culturas en la investigación.', ARRAY['8.1. Diferencia entre características cualitativas y cuantitativas en los procesos que observa.', '8.2. Utiliza eficientemente la tecnología en el proceso de experimentación.', '8.3. Presenta en forma gráfica la información obtenida.', '8.4. Emite juicios críticos con respecto a los resultados de la experimentación científica.']);
